using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Chat client (provider SDK wired through MEAI abstraction) ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var notebook = new Notebook();
AITool[] tools =
[
    AIFunctionFactory.Create(notebook.SearchWeb),
    AIFunctionFactory.Create(notebook.TakeNote),
    AIFunctionFactory.Create(notebook.GetNotes),
];

// --- Agent (Microsoft Agent Framework handles the tool-dispatch loop) ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent that investigates topics thoroughly.

        When given a research topic:
        1. Search the web 2-3 times with varied queries to gather diverse information.
        2. Take notes on the key findings from each search.
        3. After gathering enough information, retrieve your notes.
        4. Provide a well-organized summary of the main points.

        Always cite sources when possible. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings",
    tools: tools);

// --- Prompt ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

AgentResponse response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine(response.Text);

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------
partial class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];
    private static readonly HttpClient s_httpClient = new();

    [Description("Search the web for information on a given query. Returns relevant text snippets from search results.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

            var httpResponse = await s_httpClient.SendAsync(request);
            httpResponse.EnsureSuccessStatusCode();
            var html = await httpResponse.Content.ReadAsStringAsync();

            var snippets = ExtractSearchSnippets(html);
            return snippets.Length > 0
                ? snippets
                : "No relevant results found for this query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Save a research note with a title and content for later reference.")]
    public string TakeNote(
        [Description("Brief title for the note")] string title,
        [Description("Content and findings to record")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note saved: \"{title}\"";
    }

    [Description("Retrieve all research notes taken during this session.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    // --- HTML parsing helpers ---------------------------------------------------

    private static string ExtractSearchSnippets(string html)
    {
        var sb = new StringBuilder();
        var snippetMatches = SnippetRegex().Matches(html);
        var titleMatches = TitleRegex().Matches(html);

        var count = Math.Min(snippetMatches.Count, 5);
        for (var i = 0; i < count; i++)
        {
            var title = i < titleMatches.Count
                ? StripHtml(titleMatches[i].Groups[1].Value)
                : $"Result {i + 1}";
            var snippet = StripHtml(snippetMatches[i].Groups[1].Value);

            sb.AppendLine($"[{i + 1}] {title}");
            sb.AppendLine($"    {snippet}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private static string StripHtml(string html) =>
        HtmlTagRegex().Replace(System.Net.WebUtility.HtmlDecode(html), "").Trim();

    [GeneratedRegex("""class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("""class="result__a"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex TitleRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();
}

